记一次宿舍智能开关的改造前言最近突发奇想，寝室的开关可不可以做成智能开关，手机远程控制？由于我们学校寝室工作日是22:30熄灯，熄灯之后没有人主动关闭电灯开关，第二天早上就会被突然亮起的灯晃醒，很是难受，所以可以定时且可以远程的开关势在必行！ 材料清单 ESP8266-01S模块*1 CH340烧录器 继电器模块(基于ESP8266-01/01S)设计 查看详情 220V转5V模块（未购买） 杜邦线若干 点击展开代码 >## 改造流程- APP端设置1. 下载安装[blinker app](https://diandeng.tech/doc/app-download)2. 注册blinker账号，创建设备，获取并记录密钥authkey3. 选择刚刚添加的设备，添加一个按钮，案件类型选择“开关按键”- 烧写固件1. 运行Arduino IDE，填入代码，按照自己情况修改网络连接模式，上传烧录固件&gt; Arduino IDE需安装好esp32扩展 [Arduino IDE 1.8.7](https://www.arduino.cc/en/Main/Software)或更新版本 &gt; 务必使用 1.0.5 或以上release版本的 ESP32 Arduino package &gt; [安装方法](https://github.com/espressif/arduino-esp32) &gt; [下载](https://diandeng.tech/dev)并安装blinker Arduino库 &gt; Windows：将下载好的blinker库解压到 我的电脑&gt;文档&gt;Arduino&gt;libraries 文件夹中 Mac OS：将下载好的blinker库解压到 文稿&gt;Arduino&gt;libraries 文件夹中 固件示例 ``` js 点击展开代码 &gt;folded/*NodeMcu或esp-01/01s控制1路继电器，集成blinker平台，用手机app控制1路继电器开关，添加一路物理开关控制，继电器用常开（NO）模式1，继电器高电平触发时，YYXBC_HIGH = 1，YYXBC_LOW = 0继电器低电平触发时，YYXBC_HIGH = 0，YYXBC_LOW = 1const int YYXBC_HIGH = 0 ;const int YYXBC_LOW = 1 ;2，用esp-01时，物理开关接在vcc 和gpio2上，继电器接在gpio0上用nodeMcu时，物理开关接在vcc 和D4上，继电器接在D3上，下面的宏定义只能同时有一个生效//NodeMCU 继电器接D3,物理开关接D4#define LED_BUILTIN_LIGHT 0#define LED_BUILTIN_K2 2//Esp-01/01s，继电器接GPIO0,物理开关接GPIO2//#define LED_BUILTIN_LIGHT D3//#define LED_BUILTIN_K2 D43，YYXBC_BUTTON_TYPE = 1时表示物理开关为点动模式，0时表示自锁模式const int YYXBC_BUTTON_TYPE = 1;*/#define BLINKER_PRINT Serial#define BLINKER_WIFI#define BLINKER_MIOT_OUTLET // 设置小爱灯类库#define BLINKER_DUEROS_OUTLET // 设置小度灯类库#define BLINKER_ALIGENIE_OUTLET // 设置天猫灯类库#define BLINKER_WITHOUT_SSL //使用这个宏，表示不用SSL加密，可以得到更多内存//////如果要使用apconfig配网模式，打开注释掉，加让这行代码生效//#define BLINKER_APCONFIG////////如果要使用smartconfig配网模式，打开注释掉，加让这行代码生效//#define BLINKER_ESP_SMARTCONFIG//支持阳阳学编程的web wifi配网，暂时不开源//#define YYXBC_WEBCONFIG#include &lt;Blinker.h&gt;#include &lt;ESP8266WebServer.h&gt;#if (defined(YYXBC_WEBCONFIG)) #include &quot;wificfg.h&quot;#endif//char auth[] = &quot;4f8d8fc8a204&quot;;//1char auth[] = &quot;4a20dcdbc8e3&quot;;//2char ssid[] = &quot;switch&quot;;char pswd[] = &quot;sgdy11209&quot;;String version = &quot;1.0.4&quot;;//Esp-01/01s，继电器接GPIO0,物理开关接GPIO2#define LED_BUILTIN_LIGHT 0#define LED_BUILTIN_K2 2////NodeMCU 继电器接D3,物理开关接D4//#define LED_BUILTIN_LIGHT D3//#define LED_BUILTIN_K2 D4/*** * 继电器高电平触发时，YYXBC_HIGH = 1，YYXBC_LOW = 0 * 继电器低电平触发时，YYXBC_HIGH = 0，YYXBC_LOW = 1 */const int YYXBC_HIGH = 0 ;const int YYXBC_LOW = 1 ;/*** * 物理开关点动模式1，自锁模式0 */const int YYXBC_BUTTON_TYPE = 0;//http接口请求密码String httppswd = &quot;123456&quot;;bool oDuerState = YYXBC_LOW;bool oMioState = YYXBC_LOW;bool oAligenieState = YYXBC_LOW;// 新建组件对象BlinkerButton Button1(&quot;btn-abc&quot;);//webserver for siristatic ESP8266WebServer esp8266_server(80);//是否处理联网状态bool isNetConnected(){return (WiFi.status() == WL_CONNECTED);}//心跳回调void heartbeat(){ BLINKER_LOG(&quot;heartbeat,state: &quot;, digitalRead(LED_BUILTIN)); //较正app的按钮状态 if(YYXBC_HIGH == digitalRead(LED_BUILTIN_LIGHT) ){ Button1.print(&quot;on&quot;); }else{ Button1.print(&quot;off&quot;); }}//+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++//*******如果是手机app 有对设备进行操作就执行下面void button1_callback(const String &amp; state){ BLINKER_LOG(&quot;button1_callback get button state: &quot;, state); if (state == BLINKER_CMD_ON) { BLINKER_LOG(&quot;Toggle on!&quot;); if(isNetConnected())Button1.print(&quot;on&quot;); digitalWrite(LED_BUILTIN_LIGHT, YYXBC_HIGH); oDuerState = YYXBC_HIGH; oMioState =YYXBC_HIGH; oAligenieState = YYXBC_HIGH; } else if (state == BLINKER_CMD_OFF) { BLINKER_LOG(&quot;Toggle off!&quot;); if(isNetConnected())Button1.print(&quot;off&quot;); digitalWrite(LED_BUILTIN_LIGHT, YYXBC_LOW); oDuerState = YYXBC_LOW; oMioState = YYXBC_LOW; oAligenieState = YYXBC_LOW; } if(isNetConnected()){ BlinkerDuerOS.powerState(oDuerState == YYXBC_HIGH ? &quot;on&quot; : &quot;off&quot;); BlinkerDuerOS.report(); BlinkerMIOT.powerState(oMioState == YYXBC_HIGH ? &quot;on&quot; : &quot;off&quot;); BlinkerMIOT.print(); BlinkerAliGenie.powerState(oAligenieState == YYXBC_HIGH ? &quot;on&quot; : &quot;off&quot;); BlinkerAliGenie.print(); }}//+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++//*******如果小度 有对设备进行操作就执行下面void duerPowerState(const String &amp; state){ BLINKER_LOG(&quot;duerPowerState need set power state: &quot;, state); if (state == BLINKER_CMD_ON) { button1_callback(BLINKER_CMD_ON); } else if (state == BLINKER_CMD_OFF) { button1_callback(BLINKER_CMD_OFF); }}void duerQuery(int32_t queryCode){ BLINKER_LOG(&quot;DuerOS Query codes: &quot;, queryCode); switch (queryCode) { case BLINKER_CMD_QUERY_POWERSTATE_NUMBER : BLINKER_LOG(&quot;DuerOS Query power state&quot;); BlinkerDuerOS.powerState(oDuerState == YYXBC_HIGH? &quot;on&quot; : &quot;off&quot;); BlinkerDuerOS.print(); break; case BLINKER_CMD_QUERY_TIME_NUMBER : BLINKER_LOG(&quot;DuerOS Query time&quot;); BlinkerDuerOS.time(millis()); BlinkerDuerOS.print(); break; default : BlinkerDuerOS.powerState(oDuerState == YYXBC_HIGH? &quot;on&quot; : &quot;off&quot;); BlinkerDuerOS.print(); break; }}//+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++//*******如果小爱有对设备进行操作就执行下面void miotPowerState(const String &amp; state){ BLINKER_LOG(&quot;miotPowerState need set power state: &quot;, state); if (state == BLINKER_CMD_ON) { button1_callback(BLINKER_CMD_ON); } else if (state == BLINKER_CMD_OFF) { button1_callback(BLINKER_CMD_OFF); }}void miotQuery(int32_t queryCode){ BLINKER_LOG(&quot;MIOT Query codes: &quot;, queryCode); switch (queryCode) { case BLINKER_CMD_QUERY_ALL_NUMBER : BLINKER_LOG(&quot;MIOT Query All&quot;); BlinkerMIOT.powerState(oMioState == YYXBC_HIGH? &quot;on&quot; : &quot;off&quot;); BlinkerMIOT.print(); break; case BLINKER_CMD_QUERY_POWERSTATE_NUMBER : BLINKER_LOG(&quot;MIOT Query Power State&quot;); BlinkerMIOT.powerState(oMioState ==YYXBC_HIGH ? &quot;on&quot; : &quot;off&quot;); BlinkerMIOT.print(); break; default : BlinkerMIOT.powerState(oMioState ==YYXBC_HIGH ? &quot;on&quot; : &quot;off&quot;); BlinkerMIOT.print(); break; }}//+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++//*******如果天猫精灵有对设备进行操作就执行下面void aligeniePowerState(const String &amp; state){ BLINKER_LOG(&quot;aligeniePowerState need set power state: &quot;, state); if (state == BLINKER_CMD_ON) { button1_callback(BLINKER_CMD_ON); } else if (state == BLINKER_CMD_OFF) { button1_callback(BLINKER_CMD_OFF); }}void aligenieQuery(int32_t queryCode){ BLINKER_LOG(&quot;AliGenie Query codes: &quot;, queryCode); switch (queryCode) { case BLINKER_CMD_QUERY_ALL_NUMBER : BLINKER_LOG(&quot;AliGenie Query All&quot;); BlinkerAliGenie.powerState(oAligenieState == YYXBC_HIGH? &quot;on&quot; : &quot;off&quot;); BlinkerAliGenie.print(); break; case BLINKER_CMD_QUERY_POWERSTATE_NUMBER : BLINKER_LOG(&quot;AliGenie Query Power State&quot;); BlinkerAliGenie.powerState(oAligenieState == YYXBC_HIGH? &quot;on&quot; : &quot;off&quot;); BlinkerAliGenie.print(); break; default : BlinkerAliGenie.powerState(oAligenieState == YYXBC_HIGH ? &quot;on&quot; : &quot;off&quot;); BlinkerAliGenie.print(); break; }}void dataRead(const String &amp; data){ BLINKER_LOG(&quot;Blinker readString: &quot;, data);// Blinker.vibrate();// // uint32_t BlinkerTime = millis();// // Blinker.print(&quot;millis&quot;, BlinkerTime);}void setup() { // 初始化串口 Serial.begin(115200); #if defined(BLINKER_PRINT) BLINKER_DEBUG.stream(BLINKER_PRINT); #endif// //debug 命令// BLINKER_DEBUG.stream(BLINKER_PRINT);// BLINKER_DEBUG.debugAll(); // 初始化有LED的IO pinMode(LED_BUILTIN_LIGHT, OUTPUT); digitalWrite(LED_BUILTIN_LIGHT, YYXBC_LOW); pinMode(LED_BUILTIN_K2, OUTPUT);// digitalWrite(LED_BUILTIN_K2, LOW); #if (defined(YYXBC_WEBCONFIG)) //wifi 配网 WIFI_Init(); Settings&amp; cfg = getSettings(); Blinker.begin(cfg.auth.c_str(),WiFi.SSID().c_str(),WiFi.psk().c_str()); #else #if (defined(BLINKER_APCONFIG)) || (defined(BLINKER_ESP_SMARTCONFIG)) //启动配网模式用这行代码 Blinker.begin(auth); #else Blinker.begin(auth, ssid, pswd); #endif #endif Blinker.attachData(dataRead); BlinkerDuerOS.attachPowerState(duerPowerState); //小度语音操作注册函数 BlinkerDuerOS.attachQuery(duerQuery); BlinkerMIOT.attachPowerState(miotPowerState);//小爱语音操作注册函数 BlinkerMIOT.attachQuery(miotQuery); BlinkerAliGenie.attachPowerState(aligeniePowerState);//天猫语音操作注册函数 BlinkerAliGenie.attachQuery(aligenieQuery); Button1.attach(button1_callback); //注册回调函数 Blinker.attachHeartbeat(heartbeat); //启动webserver ,提供接口给siri用 esp8266_server.on(&quot;/&quot;, handleRoot); esp8266_server.on(&quot;/post&quot;, handleSetConfig); esp8266_server.onNotFound(handleNotFound); esp8266_server.begin(); Serial.println(&quot;HTTP esp8266_server started&quot;);}void loop() { static int lastms = millis(); if (millis()-lastms &gt; 30000) { lastms = millis(); Serial.printf(PSTR(&quot;Running (%s),state(%s),version %s for %d Free mem=%d
&quot;), WiFi.localIP().toString().c_str(), oAligenieState == YYXBC_HIGH ? &quot;YYXBC_HIGH&quot; : &quot;CLOES&quot;, version.c_str(), lastms/1000, ESP.getFreeHeap()); } Blinker.run();//运行Blinker esp8266_server.handleClient();// 处理http服务器访问 //检查物理开关状态 bool bret = false; if(YYXBC_BUTTON_TYPE == 1){ bret = btnHandler1(); }else{ bret = btnHandler2(); } /* *连续5次开关，时间5秒内，认为是要进入配网模式，重启进入配网模式 */ //物理开关开、关次数，1秒内计入 static int physics_count = 0; static int lastphysicsms = 0; if(bret ){ Serial.println(&quot;物理开关被触发&quot;); Serial.println(millis()-lastphysicsms); if (millis()-lastphysicsms &lt; 2000) { Serial.println(physics_count); Serial.print(&quot;/5物理开关触发配网模式...&quot;); physics_count++; }else{ physics_count = 0; } lastphysicsms = millis(); } //进入配网模式，重启esp8266 if(physics_count &gt;= 4){ Serial.println(&quot;正在重启esp8266，启动后进入配网模式...&quot;); #if (defined(YYXBC_WEBCONFIG)) WIFI_RestartToCfg(); #else ESP.restart(); #endif } }//+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++//*******如果iOS的siri有对设备进行操作就执行下面 void handleRoot() { //处理网站根目录“/”的访问请求 String data = &quot;&lt;html&gt;&quot;; data += &quot;&lt;head&gt;&lt;title&gt;设置&lt;/title&gt;&lt;/head&gt;&quot;; data += &quot;&lt;body&gt;&quot;; data +=&quot; &lt;p&gt;ESP8266 智能开关，技术支持 微信:yyxbc2010&lt;/p&gt;&lt;hr&gt;&quot;; data +=&quot; &lt;p&gt;SSID:&quot;+ WiFi.SSID() + &quot;&lt;/p&gt;&lt;hr&gt;&quot;; data +=&quot; &lt;p&gt;PSW:&quot;+ WiFi.psk() + &quot;&lt;/p&gt;&lt;hr&gt;&quot;; data += &quot;&lt;/body&gt;&quot;; data += &quot;&lt;/html&gt;&quot;; esp8266_server.send(200, &quot;text/html; charset=utf-8&quot;, data); } void handleSetConfig() { //处理来自siri的访问请求 if (esp8266_server.method() != HTTP_POST) { esp8266_server.send(405, &quot;text/plain&quot;, &quot;Method Not Allowed&quot;); } else {// String message = &quot;POST form was:
&quot;; String btnName,btnState,btnPswd; for (uint8_t i = 0; i &lt; esp8266_server.args(); i++) { String name = esp8266_server.argName(i); if(name == &quot;btn&quot;) { btnName = esp8266_server.arg(i); } else if (name == &quot;state&quot;){ btnState = esp8266_server.arg(i); } else if (name == &quot;passwd&quot;){ btnPswd = esp8266_server.arg(i); } } if(btnPswd != httppswd){ String message = &quot;{\&quot;errcode\&quot;:0,\&quot;msg\&quot;:\&quot;password error\&quot;}&quot;; esp8266_server.send(200, &quot;text/html; charset=utf-8&quot;, message); return; } if(btnName.length() &gt;0 &amp;&amp; btnState.length() &gt;0) { //开关btn-abc if(btnName == &quot;btn-1&quot;){ if(btnState == &quot;on&quot;){ button1_callback( BLINKER_CMD_ON); }else if (btnState == &quot;off&quot;){ button1_callback( BLINKER_CMD_OFF); } } } String message = &quot;{\&quot;errcode\&quot;:0,\&quot;msg\&quot;:\&quot; ok\&quot;}&quot;; esp8266_server.send(200, &quot;text/html; charset=utf-8&quot;, message); }}// 设置处理404情况的函数'handleNotFound'void handleNotFound(){ // digitalWrite(led, 1); String message = &quot;File Not Found

&quot;; message += &quot;URI: &quot;; message += esp8266_server.uri(); message += &quot;
Method: &quot;; message += (esp8266_server.method() == HTTP_GET) ? &quot;GET&quot; : &quot;POST&quot;; message += &quot;
Arguments: &quot;; message += esp8266_server.args(); message += &quot;
&quot;; for (uint8_t i = 0; i &lt; esp8266_server.args(); i++) { message += &quot; &quot; + esp8266_server.argName(i) + &quot;: &quot; + esp8266_server.arg(i) + &quot;
&quot;; } esp8266_server.send(404, &quot;text/plain&quot;, message);}//点动模式按钮，监听按钮状态，执行相应处理bool btnHandler1(){ static bool oButtonState = false; int state1 = digitalRead(LED_BUILTIN_K2); //按钮状态 int state2 = digitalRead(LED_BUILTIN_LIGHT); //灯的状态 if(state1 == HIGH ) { if(oButtonState){ if(state2 == YYXBC_HIGH ) { button1_callback(BLINKER_CMD_OFF); Serial.println(&quot;按钮对灯已执行关闭&quot;); }else{ button1_callback(BLINKER_CMD_ON); Serial.println(&quot;按钮对灯已执行打开&quot;); } oButtonState = false; return true; } }else{ oButtonState = true; } return false;}//自锁模式按钮，监听按钮状态，执行相应处理bool btnHandler2(){ static bool is_btn = digitalRead(LED_BUILTIN_K2);//按钮的标志位，用来逻辑处理对比，判断按钮有没有改变状态 bool is = digitalRead(LED_BUILTIN_K2); //按钮状态 if ( is != is_btn) { bool is_led = digitalRead(LED_BUILTIN_LIGHT); digitalWrite(LED_BUILTIN_LIGHT, !is_led); if (is_led == YYXBC_HIGH) { button1_callback(BLINKER_CMD_OFF); Serial.println(&quot;按钮对灯已执行关闭&quot;); } else { button1_callback(BLINKER_CMD_ON); Serial.println(&quot;按钮对灯已执行打开&quot;); } is_btn = digitalRead(LED_BUILTIN_K2); //更新按钮状态 return true; } return false;}
